components.openAPISpec:
openapi: 3.0.3
info:
  title: Todo API
  version: 1.0.0
servers:
  - url: /v1
paths:
  /health:
    get:
      summary: Health check
      responses:
        '200': { description: OK }
  /ready:
    get:
      summary: Readiness check (verifies DB)
      responses:
        '200': { description: Ready }
        '503': { description: Not ready }
  /todos:
    get:
      summary: List todos
      parameters:
        - { name: limit, in: query, schema: { type: integer, default: 20, maximum: 100 } }
        - { name: offset, in: query, schema: { type: integer, default: 0 } }
        - { name: completed, in: query, schema: { type: boolean } }
        - { name: priority, in: query, schema: { type: string, enum: [low, medium, high] } }
        - { name: due_from, in: query, schema: { type: string, format: date-time } }
        - { name: due_to, in: query, schema: { type: string, format: date-time } }
        - { name: sort, in: query, schema: { type: string, enum: [created_at, due_date, priority] } }
        - { name: order, in: query, schema: { type: string, enum: [asc, desc], default: asc } }
      responses:
        '200':
          description: List
          content:
            application/json:
              schema:
                type: object
                properties:
                  items: { type: array, items: { $ref: '#/components/schemas/Todo' } }
                  total: { type: integer }
                  limit: { type: integer }
                  offset: { type: integer }
    post:
      summary: Create todo
      requestBody:
        required: true
        content:
          application/json:
            schema: { $ref: '#/components/schemas/TodoCreate' }
      responses:
        '201': { description: Created, content: { application/json: { schema: { $ref: '#/components/schemas/Todo' } } } }
        '400': { $ref: '#/components/responses/Error' }
  /todos/{id}:
    parameters:
      - { name: id, in: path, required: true, schema: { type: string } }
    get:
      responses:
        '200': { description: OK, content: { application/json: { schema: { $ref: '#/components/schemas/Todo' } } } }
        '404': { $ref: '#/components/responses/Error' }
    put:
      requestBody: { required: true, content: { application/json: { schema: { $ref: '#/components/schemas/TodoUpdate' } } } }
      responses:
        '200': { description: OK, content: { application/json: { schema: { $ref: '#/components/schemas/Todo' } } } }
        '400': { $ref: '#/components/responses/Error' }
        '404': { $ref: '#/components/responses/Error' }
    delete:
      responses:
        '204': { description: Deleted }
        '404': { $ref: '#/components/responses/Error' }
components:
  schemas:
    Todo:
      type: object
      properties:
        id: { type: string }
        title: { type: string }
        description: { type: string }
        completed: { type: boolean }
        due_date: { type: string, format: date-time }
        priority: { type: string, enum: [low, medium, high] }
        created_at: { type: string, format: date-time }
        updated_at: { type: string, format: date-time }
    TodoCreate:
      type: object
      required: [title]
      properties:
        title: { type: string, maxLength: 200 }
        description: { type: string, maxLength: 2000 }
        due_date: { type: string, format: date-time }
        priority: { type: string, enum: [low, medium, high], default: medium }
    TodoUpdate:
      type: object
      properties:
        title: { type: string, maxLength: 200 }
        description: { type: string, maxLength: 2000 }
        due_date: { type: string, format: date-time }
        priority: { type: string, enum: [low, medium, high] }
        completed: { type: boolean }
    ErrorResponse:
      type: object
      properties:
        code: { type: string }
        message: { type: string }
        details:
          type: array
          items:
            type: object
            properties:
              field: { type: string }
              message: { type: string }
  responses:
    Error:
      description: Error
      content:
        application/json:
          schema: { $ref: '#/components/schemas/ErrorResponse' }
